events.code:
with enriched as (
  select * from {{ ref('stg_orders') }}
),
tickets as (
  select order_id, count(ticket_id) as support_ticket_count
  from {{ ref('stg_support_tickets') }}
  group by 1
)
select
  o.*,
  coalesce(t.ticket_status, 0) as support_ticket_count
from enriched o
left join tickets t on o.order_id = t.order_id
